import React, { useEffect, useState } from 'react';
import { GetSeasons } from "../services/season-service";
import { Season } from "../objects/season";
import SeasonCard from "../atoms/card/season-card";
import { useNavigate } from "react-router-dom";
import { GetPlayers } from '../services/player-service';
import { Player } from '../objects/player';
import PlayerCard from '../atoms/card/player-card';
import { GameStat } from '../objects/game-stat';
import { GetGameStats } from '../services/game-stat-service';
import GameStatTable from '../components/game-stats/game-stat-table';

const Home = () => {
    
    const navigate = useNavigate();
    const [seasons, setData] = useState<Season[] | null>(null);
    const [players, setPlayerData] = useState<Player[] | null>(null); 
    const [gameStats, setGameStats] = useState<GameStat[] | null>(null);

    useEffect(() => {
        GetSeasons().then(seasons => setData(seasons));
    }, []);

    useEffect(() => {
        GetPlayers().then(players => setPlayerData(players));
    }, []);

    useEffect(() => {
        GetGameStats().then(gameStats => setGameStats(gameStats));
    }, []);

    const handleClick = (seasonId : any) => navigate('/Fixtures/' + seasonId);

    return(
        <>
            <div className="row">
                {   seasons ? seasons.map((item) => (                        
                        <SeasonCard key={item.id} season={item} handleClick={handleClick} > </SeasonCard>
                    )) : <p>Loading Seasons...</p>}
            </div>

            <div className="row">
                {   players ? players.map((item) => (                        
                        <PlayerCard player={item}></PlayerCard>
                    )) : <p>Loading Players...</p>}
            </div>  

             <div className="row">
                {   gameStats ? <GameStatTable gameStats={gameStats}></GameStatTable>
                    : <p>Loading Stats...</p>}
            </div>        
        </>
    )
}
export default Home;
